-- Generated by scripts/generate-sjenica-jan-feb-import.mjs
-- Fixed-ID version. Safe only if supplier IDs match between environments.
-- Provided dev/prod supplier lists were compared and matched.
-- Duplicate name note: Ujkanovic/Ujanovic Naser is mapped to supplier_id 33.
begin;

select
  87,
  coalesce((select max(order_index) from public.suppliers), 0) + 1,
  'Almir',
  'Bogu\u0107anin',
  'Sjenica',
  'Srbija'
where not exists (
  select 1
  from public.suppliers
  where id = 87
);

select case
  when exists (select 1 from public.suppliers where id = 87 and (first_name not in ('Almir') or last_name not in ('Bogu\u0107anin', 'Bogucanin')))
    then cast('manual supplier id conflict' as integer)
  when exists (select 1 from public.suppliers where first_name in ('Almir') and last_name in ('Bogu\u0107anin', 'Bogucanin') and id <> 87)
    then cast('manual supplier name conflict' as integer)
  else 1
end;

select setval(pg_get_serial_sequence('public.suppliers', 'id'), greatest(coalesce((select max(id) from public.suppliers), 0), 87), true);

on conflict (supplier_id, date) do update
set qty = excluded.qty,
    fat_pct = excluded.fat_pct;

commit;
